const fs = require('fs');
const path = '/home/node/.n8n/rsvps.json';

// Check API key
const query = $input.first().json.query || {};
const expectedKey = process.env.RSVP_EXPORT_KEY || 'covenant-day-export-2026';

if (query.key !== expectedKey) {
  return [{ json: { error: 'Unauthorized', status: 401 } }];
}

// Read RSVPs
let rsvps = [];
try {
  const content = fs.readFileSync(path, 'utf8');
  rsvps = JSON.parse(content);
} catch (e) {
  rsvps = [];
}

// Filter by coupleSlug if provided
const slug = query.slug;
if (slug) {
  rsvps = rsvps.filter(r => r.coupleSlug === slug);
}

const attending = rsvps.filter(r => r.attending === 'yes');
const declining = rsvps.filter(r => r.attending === 'no');
const totalGuests = attending.reduce((sum, r) => sum + (parseInt(r.guests) || 1), 0);

return [{ json: {
  rsvps,
  summary: {
    total: rsvps.length,
    attending: attending.length,
    declining: declining.length,
    totalGuests
  }
}}];
